const body = $input.first().json.body || $input.first().json;
const text = (body.message || body.text || body.body || '').toLowerCase();
const email = (body.email || body.from || '').toLowerCase().trim();
const name = body.name || body.sender || '';

let score = 40;
let seriousness = 'unknown';
let timeframe = 'unknown';
let temp = 'cold';

if (text.includes('ready') || text.includes('let\'s go') || text.includes('sign me up')) score += 30;
if (text.includes('how much') || text.includes('pricing') || text.includes('cost')) score += 20;
if (text.includes('call') || text.includes('talk') || text.includes('meeting')) score += 15;
if (text.includes('interested') || text.includes('tell me more')) score += 10;
if (text.includes('asap') || text.includes('this week') || text.includes('immediately')) { score += 15; timeframe = 'immediate'; }
if (text.includes('next month') || text.includes('soon')) { score += 5; timeframe = '1_month'; }

if (score >= 80) { temp = 'hot'; seriousness = 'high'; }
else if (score >= 60) { temp = 'warm'; seriousness = 'medium'; }
else { seriousness = 'low'; }

return [{ json: { email, name, source: body.source || 'sales_inbox', temperature: temp, last_engagement_score: Math.min(score, 100), estimated_seriousness: seriousness, time_to_close_estimate: timeframe, last_engagement_at: new Date().toISOString(), next_action: temp === 'hot' ? 'Book call immediately' : 'Send intro email', notes: text.slice(0, 500), status: 'new' } }];
